function.arguments:
{"script":"set -e
# Create calc script (try /usr/local/bin, fallback to ~/.local/bin)
TARGET_DIR=/usr/local/bin
TARGET="$TARGET_DIR/calc"
PYTHON_SCRIPT='#!/usr/bin/env python3
import sys,ast,operator

ops = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.UAdd: lambda x: x,
    ast.USub: operator.neg,
}

def eval_node(node):
    if isinstance(node, ast.Expression):
        return eval_node(node.body)
    if isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError('Unsupported constant')
    if hasattr(ast, 'Num') and isinstance(node, ast.Num):
        return node.n
    if isinstance(node, ast.BinOp):
        left = eval_node(node.left)
        right = eval_node(node.right)
        op_type = type(node.op)
        if op_type in ops:
            return ops[op_type](left, right)
        raise ValueError('Unsupported operator')
    if isinstance(node, ast.UnaryOp):
        operand = eval_node(node.operand)
        op_type = type(node.op)
        if op_type in ops:
            return ops[op_type](operand)
        raise ValueError('Unsupported unary operator')
    if isinstance(node, ast.Paren):
        return eval_node(node.value)
    raise ValueError('Unsupported expression: %s' % ast.dump(node))

def format_num(x):
    if isinstance(x, bool):
        # bool is subclass of int, but not desired
        raise ValueError('Booleans not allowed')
    if isinstance(x, int):
        return str(x)
    if isinstance(x, float):
        if x.is_integer():
            return str(int(x))
        s = '{:.10f}'.format(x).rstrip('0').rstrip('.')
        if s == '-0':
            return '0'
        return s
    return str(x)

if __name__ == '__main__':
    if len(sys.argv) > 1:
        expr = ' '.join(sys.argv[1:])
    else:
        # Read from stdin if no args
        expr = sys.stdin.read().strip()
    if not expr:
        sys.exit(0)
    try:
        node = ast.parse(expr, mode='eval')
        res = eval_node(node)
        print(format_num(res))
    except Exception as e:
        sys.stderr.write('Error: %s\n' % e)
        sys.exit(2)
'

# Try to write to /usr/local/bin; if not writable, fallback to ~/.local/bin
if [ ! -w "$TARGET_DIR" ]; then
  TARGET_DIR="$HOME/.local/bin"
  mkdir -p "$TARGET_DIR"
  TARGET="$TARGET_DIR/calc"
fi

cat > "$TARGET" <<'PY'
${PYTHON_SCRIPT}
PY

chmod +x "$TARGET"

echo "Created calc at: $TARGET"

echo "Example: calc 6 * (9 / 3) + 7 ->"
"$TARGET" 6 '*' '(' 9 '/' 3 ')' '+' 7
"}
